module rc_oscillator (
    input wire clk,
    input wire rst,
    input wire enable,
    output reg out
);
    reg [23:0] countdown_timer;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            countdown_timer <= 0;
            out <= 0;
        end else if (enable) begin
            if (countdown_timer == 24'd12499999) begin // Adjust this value for frequency
                out <= ~out;
                countdown_timer <= 0;
            end else begin
                countdown_timer <= countdown_timer + 1;
            end
        end else begin
            out <= 0; // Disable output when not enabled
        end
    end
endmodule
